INSERT INTO reviews (id, user_id, ground_id, rating, review_text, created_at) VALUES
('71000000-0000-0000-0000-000000000001', 'a1000000-0000-0000-0000-000000000009', 'c1000000-0000-0000-0000-000000000001', 5, 'Excellent facilities! Best futsal ground in Kathmandu. Well-maintained turf and great lighting.', '2024-04-16 10:00:00'),
('71000000-0000-0000-0000-000000000002', 'a1000000-0000-0000-0000-000000000010', 'c1000000-0000-0000-0000-000000000001', 5, 'Amazing experience! The staff is very professional and the ground quality is top-notch.', '2024-04-17 11:30:00'),
('71000000-0000-0000-0000-000000000003', 'a1000000-0000-0000-0000-000000000011', 'c1000000-0000-0000-0000-000000000001', 5, 'Perfect ground for playing. Clean changing rooms and excellent booking system.', '2024-04-18 14:00:00'),
('71000000-0000-0000-0000-000000000004', 'a1000000-0000-0000-0000-000000000012', 'c1000000-0000-0000-0000-000000000004', 5, 'Champions Ground lives up to its name! Premium quality turf and great ambiance.', '2024-04-20 09:00:00'),
('71000000-0000-0000-0000-000000000005', 'a1000000-0000-0000-0000-000000000013', 'c1000000-0000-0000-0000-000000000004', 5, 'Highly recommended! Best ground in Pulchowk area. Very well maintained.', '2024-04-21 15:30:00'),
('71000000-0000-0000-0000-000000000006', 'a1000000-0000-0000-0000-000000000014', 'c1000000-0000-0000-0000-000000000004', 5, 'Outstanding facility with excellent service. Will definitely come back.', '2024-04-22 10:00:00'),
('71000000-0000-0000-0000-000000000007', 'a1000000-0000-0000-0000-000000000015', 'c1000000-0000-0000-0000-000000000007', 5, 'Star Sports Complex is the best! Great ground, fair pricing, and friendly staff.', '2024-04-24 12:00:00'),
('71000000-0000-0000-0000-000000000008', 'a1000000-0000-0000-0000-000000000016', 'c1000000-0000-0000-0000-000000000007', 5, 'Wonderful experience! The ground is always well-maintained and clean.', '2024-04-25 09:30:00'),
('71000000-0000-0000-0000-000000000009', 'a1000000-0000-0000-0000-000000000017', 'c1000000-0000-0000-0000-000000000010', 5, 'Victory Premium Court is absolutely amazing! Top quality turf and facilities.', '2024-04-26 11:00:00'),
('71000000-0000-0000-0000-000000000010', 'a1000000-0000-0000-0000-000000000018', 'c1000000-0000-0000-0000-000000000012', 5, 'Prime Arena exceeded my expectations! Excellent ground with great amenities.', '2024-04-27 13:30:00'),
('71000000-0000-0000-0000-000000000011', 'a1000000-0000-0000-0000-000000000019', 'c1000000-0000-0000-0000-000000000014', 5, 'Golden Goal Arena is phenomenal! Best futsal experience in Lalitpur.', '2024-04-28 10:00:00'),
('71000000-0000-0000-0000-000000000012', 'a1000000-0000-0000-0000-000000000020', 'c1000000-0000-0000-0000-000000000017', 5, 'Supreme Main Court is exceptional! Premium facilities worth every rupee.', '2024-04-29 14:00:00');
INSERT INTO reviews (id, user_id, ground_id, rating, review_text, created_at) VALUES
('71000000-0000-0000-0000-000000000013', 'a1000000-0000-0000-0000-000000000021', 'c1000000-0000-0000-0000-000000000001', 4, 'Very good ground overall. Could improve parking facilities but great playing experience.', '2024-04-19 11:00:00'),
('71000000-0000-0000-0000-000000000014', 'a1000000-0000-0000-0000-000000000022', 'c1000000-0000-0000-0000-000000000002', 4, 'Good quality turf and decent facilities. Slightly expensive but worth it.', '2024-04-20 15:00:00'),
('71000000-0000-0000-0000-000000000015', 'a1000000-0000-0000-0000-000000000023', 'c1000000-0000-0000-0000-000000000003', 4, 'Indoor court is nice but could use better ventilation. Otherwise great facility.', '2024-04-21 09:30:00'),
('71000000-0000-0000-0000-000000000016', 'a1000000-0000-0000-0000-000000000024', 'c1000000-0000-0000-0000-000000000004', 4, 'Champions Ground is really good. Small waiting area but excellent playing surface.', '2024-04-23 12:30:00'),
('71000000-0000-0000-0000-000000000017', 'a1000000-0000-0000-0000-000000000025', 'c1000000-0000-0000-0000-000000000005', 4, 'Practice ground is decent for the price. Good for casual games.', '2024-04-24 08:00:00'),
('71000000-0000-0000-0000-000000000018', 'a1000000-0000-0000-0000-000000000009', 'c1000000-0000-0000-0000-000000000006', 4, 'VIP Court is premium quality. Only issue is booking availability during peak hours.', '2024-04-25 16:00:00'),
('71000000-0000-0000-0000-000000000019', 'a1000000-0000-0000-0000-000000000010', 'c1000000-0000-0000-0000-000000000008', 4, 'Star Field 2 is good. Well-maintained ground with friendly staff.', '2024-04-26 10:30:00'),
('71000000-0000-0000-0000-000000000020', 'a1000000-0000-0000-0000-000000000011', 'c1000000-0000-0000-0000-000000000011', 4, 'Victory Standard Court offers good value. Clean and well-maintained.', '2024-04-27 14:30:00'),
('71000000-0000-0000-0000-000000000021', 'a1000000-0000-0000-0000-000000000012', 'c1000000-0000-0000-0000-000000000013', 4, 'Prime Express Court is convenient and affordable. Good for quick games.', '2024-04-28 09:00:00'),
('71000000-0000-0000-0000-000000000022', 'a1000000-0000-0000-0000-000000000013', 'c1000000-0000-0000-0000-000000000015', 4, 'Golden Court B is nice. A bit crowded during weekends but good overall.', '2024-04-29 11:30:00');
INSERT INTO reviews (id, user_id, ground_id, rating, review_text, created_at) VALUES
('71000000-0000-0000-0000-000000000023', 'a1000000-0000-0000-0000-000000000014', 'c1000000-0000-0000-0000-000000000005', 3, 'Average facility. Concrete surface is okay but not ideal for serious play.', '2024-04-23 13:00:00'),
('71000000-0000-0000-0000-000000000024', 'a1000000-0000-0000-0000-000000000015', 'c1000000-0000-0000-0000-000000000009', 3, 'Mini court is decent for practice. Surface could be better maintained.', '2024-04-24 15:30:00'),
('71000000-0000-0000-0000-000000000025', 'a1000000-0000-0000-0000-000000000016', 'c1000000-0000-0000-0000-000000000011', 3, 'Standard court is acceptable. Nothing special but gets the job done.', '2024-04-26 12:00:00'),
('71000000-0000-0000-0000-000000000026', 'a1000000-0000-0000-0000-000000000017', 'c1000000-0000-0000-0000-000000000016', 3, 'Mini ground is fine for casual play. Concrete surface is a bit rough.', '2024-04-27 10:00:00'),
('71000000-0000-0000-0000-000000000027', 'a1000000-0000-0000-0000-000000000018', 'c1000000-0000-0000-0000-000000000018', 3, 'Practice area is okay. Could improve lighting and changing rooms.', '2024-04-28 16:00:00');
INSERT INTO reviews (id, user_id, ground_id, rating, review_text, created_at) VALUES
('71000000-0000-0000-0000-000000000028', 'a1000000-0000-0000-0000-000000000019', 'c1000000-0000-0000-0000-000000000009', 2, 'Below expectations. Surface is uneven and maintenance is lacking.', '2024-04-25 11:00:00'),
('71000000-0000-0000-0000-000000000029', 'a1000000-0000-0000-0000-000000000020', 'c1000000-0000-0000-0000-000000000016', 2, 'Not satisfied with the facility. Concrete surface is quite rough and poorly maintained.', '2024-04-29 09:30:00');
INSERT INTO reviews (id, user_id, ground_id, rating, review_text, created_at) VALUES
('71000000-0000-0000-0000-000000000030', 'a1000000-0000-0000-0000-000000000021', 'c1000000-0000-0000-0000-000000000009', 1, 'Very disappointed. Ground was not clean and staff was unprofessional. Will not return.', '2024-04-30 14:00:00');
